def _dbt_measure_to_nested(dbt_measure: DbtMeasure) -> DbtMeasureNested:
    """Convert flat DbtMeasure to nested format."""
    attrs = DbtMeasureAttributes()
    _populate_dbt_measure_attrs(attrs, dbt_measure)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_measure, _DBT_MEASURE_REL_FIELDS, DbtMeasureRelationshipAttributes
    )
    return DbtMeasureNested(
        guid=dbt_measure.guid,
        type_name=dbt_measure.type_name,
        status=dbt_measure.status,
        version=dbt_measure.version,
        create_time=dbt_measure.create_time,
        update_time=dbt_measure.update_time,
        created_by=dbt_measure.created_by,
        updated_by=dbt_measure.updated_by,
        classifications=dbt_measure.classifications,
        classification_names=dbt_measure.classification_names,
        meanings=dbt_measure.meanings,
        labels=dbt_measure.labels,
        business_attributes=dbt_measure.business_attributes,
        custom_attributes=dbt_measure.custom_attributes,
        pending_tasks=dbt_measure.pending_tasks,
        proxy=dbt_measure.proxy,
        is_incomplete=dbt_measure.is_incomplete,
        provenance_type=dbt_measure.provenance_type,
        home_id=dbt_measure.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_measure_from_nested(nested: DbtMeasureNested) -> DbtMeasure:
    """Convert nested format to flat DbtMeasure."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else DbtMeasureAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_MEASURE_REL_FIELDS,
        DbtMeasureRelationshipAttributes,
    )
    return DbtMeasure(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dbt_measure_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_measure_to_nested_bytes(dbt_measure: DbtMeasure, serde: Serde) -> bytes:
    """Convert flat DbtMeasure to nested JSON bytes."""
    return serde.encode(_dbt_measure_to_nested(dbt_measure))


def _dbt_measure_from_nested_bytes(data: bytes, serde: Serde) -> DbtMeasure:
    """Convert nested JSON bytes to flat DbtMeasure."""
    nested = serde.decode(data, DbtMeasureNested)
    return _dbt_measure_from_nested(nested)


